@Directive({
  selector: '[appIf]',
  standalone: true
})
export class IfDirective {
  constructor(
    private template: TemplateRef<any>,
    private viewContainer: ViewContainerRef
  ) {}

  @Input() set appIf(show: boolean) {
    this.viewContainer.clear();

    if (show) {
      this.viewContainer.createEmbeddedView(this.template);
    }
  }
}

